            },
            {
                "@type": "DefinedTerm",
                "name": "Section 47(xiv) Income Tax Act 1961",
                "description": "Special exemption treating the succession of a sole proprietorship by a company as a non-transfer for capital gains, subject to four cumulative conditions including 50 percent voting power held by the proprietor for 5 years from succession."
            },
            {
                "@type": "DefinedTerm",
