            },
            {
                "@type": "DefinedTerm",
                "name": "Section 149(3) Companies Act 2013",
                "description": "Requires at least one director of every company to have stayed in India for at least 182 days during the previous financial year - the Indian resident director requirement."
            },
            {
                "@type": "DefinedTerm",
